// Generate domain variations using data-backed cold email best practices
// Sources: Instantly, SmartLead, Salesforge, Allegrow deliverability data
// Rules: branded prefixes/suffixes only, .com first, .io second (half spam rate), .net third
// NEVER: hyphens, numbers, .co (higher spam), .xyz/.biz, industry words that look like separate businesses
const config = $input.first().json;
const brand = config.brand_name; // e.g. 'ph6coffee'

// Tier 1: Branded prefixes + .com (recommended by Instantly, SmartLead, Salesforge)
const prefixes = ['get', 'try', 'hi', 'hello', 'join', 'start'];
// Tier 2: Branded suffixes + .com (recommended by Saleshandy, DFYMeetings)
const suffixes = ['hq', 'team', 'group'];
// Tier 3: TLD swaps (Allegrow data: .io = half expected spam rate, .net = proportional, .co = AVOID)
const safeTlds = ['.io', '.net'];

const domains = new Set();

// Prefix + full brand + .com (highest priority)
for (const prefix of prefixes) {
  domains.add(`${prefix}${brand}.com`);
}

// Full brand + suffix + .com
for (const suffix of suffixes) {
  domains.add(`${brand}${suffix}.com`);
}

// TLD swaps of the base brand (only .io and .net - skip .co per Allegrow data)
for (const tld of safeTlds) {
  domains.add(`${brand}${tld}`);
}

// Top prefix combos with .io (strong deliverability)
domains.add(`get${brand}.io`);
domains.add(`try${brand}.io`);

return Array.from(domains).map(d => ({ json: { domain: d, brand: brand } }));

// Analyze DNS results to determine availability
const items = $input.all();
const domains = $('Generate Domain Variations').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const dnsResult = items[i].json;
  const domainInfo = domains[i]?.json || {};

  // Status 3 = NXDOMAIN (domain doesn't exist = available)
  // Status 0 = NOERROR (domain exists = taken)
  const status = dnsResult.Status;
  const isAvailable = status === 3;
  const hasRecords = (dnsResult.Answer || []).length > 0;

  results.push({
    json: {
      domain: domainInfo.domain,
      available: isAvailable,
      dns_status: status,
      has_dns_records: hasRecords,
      registrar_check_needed: isAvailable, // Available domains should be verified at registrar
      checked_at: new Date().toISOString()
    }
  });
}

// Sort: available first, then by domain name
return results.sort((a, b) => {
  if (a.json.available && !b.json.available) return -1;
  if (!a.json.available && b.json.available) return 1;
  return a.json.domain.localeCompare(b.json.domain);
});
